// ============================================================================
// PieceTable - Empty Document
// ============================================================================

TEST(piece_table_empty) {
    PieceTable pt;
    TEST_ASSERT_EQ(pt.total_length(), 0u);
    TEST_ASSERT_TRUE(pt.empty());
    TEST_ASSERT_EQ(pt.piece_count(), 0u);
}

TEST(piece_table_init_empty_string) {
    PieceTable pt;
    pt.init_from_string("", 0);
    TEST_ASSERT_EQ(pt.total_length(), 0u);
    TEST_ASSERT_TRUE(pt.empty());
}

TEST(piece_table_init_null) {
    PieceTable pt;
    pt.init_from_string(nullptr, 0);
    TEST_ASSERT_EQ(pt.total_length(), 0u);
    TEST_ASSERT_TRUE(pt.empty());
}

// ============================================================================
// PieceTable - Basic Initialization
// ============================================================================

TEST(piece_table_init_simple) {
    PieceTable pt;
    pt.init_from_string("hello", 5);

    TEST_ASSERT_EQ(pt.total_length(), 5u);
    TEST_ASSERT_FALSE(pt.empty());
    TEST_ASSERT_EQ(pt.piece_count(), 1u);
}

TEST(piece_table_get_text) {
    PieceTable pt;
    pt.init_from_string("hello world", 11);

    char buf[32] = {0};
    size_t len = pt.get_text(0, buf, sizeof(buf));

    TEST_ASSERT_EQ(len, 11u);
    TEST_ASSERT_STREQ(buf, "hello world");
}

TEST(piece_table_get_text_partial) {
    PieceTable pt;
    pt.init_from_string("hello world", 11);

    char buf[6] = {0};
    size_t len = pt.get_text(0, buf, 5);

    TEST_ASSERT_EQ(len, 5u);
    TEST_ASSERT_MEMEQ(buf, "hello", 5);
}

TEST(piece_table_get_text_offset) {
    PieceTable pt;
    pt.init_from_string("hello world", 11);

    char buf[32] = {0};
    size_t len = pt.get_text(6, buf, sizeof(buf));

    TEST_ASSERT_EQ(len, 5u);
    TEST_ASSERT_STREQ(buf, "world");
}

// ============================================================================
// PieceTable - Insert Operations
// ============================================================================

TEST(piece_table_insert_empty_doc) {
    PieceTable pt;
    TEST_ASSERT_TRUE(pt.insert(0, "hello", 5));

    char buf[32] = {0};
    pt.get_text(0, buf, sizeof(buf));
    TEST_ASSERT_STREQ(buf, "hello");
    TEST_ASSERT_EQ(pt.total_length(), 5u);
}

TEST(piece_table_insert_at_start) {
    PieceTable pt;
    pt.init_from_string("world", 5);

    TEST_ASSERT_TRUE(pt.insert(0, "hello ", 6));

    char buf[32] = {0};
    pt.get_text(0, buf, sizeof(buf));
    TEST_ASSERT_STREQ(buf, "hello world");
    TEST_ASSERT_EQ(pt.total_length(), 11u);
}

TEST(piece_table_insert_at_end) {
    PieceTable pt;
    pt.init_from_string("hello", 5);

    TEST_ASSERT_TRUE(pt.insert(5, " world", 6));

    char buf[32] = {0};
    pt.get_text(0, buf, sizeof(buf));
    TEST_ASSERT_STREQ(buf, "hello world");
}

TEST(piece_table_insert_in_middle) {
    PieceTable pt;
    pt.init_from_string("hello", 5);

    TEST_ASSERT_TRUE(pt.insert(2, "XX", 2));

    char buf[32] = {0};
    pt.get_text(0, buf, sizeof(buf));
    TEST_ASSERT_STREQ(buf, "heXXllo");
    TEST_ASSERT_EQ(pt.total_length(), 7u);
}

TEST(piece_table_insert_multiple) {
    PieceTable pt;
    pt.init_from_string("ac", 2);

    TEST_ASSERT_TRUE(pt.insert(1, "b", 1));

    char buf[32] = {0};
    pt.get_text(0, buf, sizeof(buf));
    TEST_ASSERT_STREQ(buf, "abc");

    // Insert at different positions
    TEST_ASSERT_TRUE(pt.insert(0, "X", 1));
    pt.get_text(0, buf, sizeof(buf));
    TEST_ASSERT_STREQ(buf, "Xabc");

    TEST_ASSERT_TRUE(pt.insert(4, "Y", 1));
    pt.get_text(0, buf, sizeof(buf));
    TEST_ASSERT_STREQ(buf, "XabcY");
}

TEST(piece_table_insert_out_of_bounds) {
    PieceTable pt;
    pt.init_from_string("hello", 5);

    // Insert beyond end should fail
    TEST_ASSERT_FALSE(pt.insert(10, "X", 1));

    // Content should be unchanged
    char buf[32] = {0};
    pt.get_text(0, buf, sizeof(buf));
    TEST_ASSERT_STREQ(buf, "hello");
}

