// ============================================================================
// PieceTable - Insert + Delete Combined
// ============================================================================

TEST(piece_table_insert_then_delete) {
    PieceTable pt;
    pt.init_from_string("hello", 5);

    pt.insert(2, "XX", 2);
    // Now: heXXllo

    pt.delete_range(2, 2);
    // Back to: hello

    char buf[32] = {0};
    pt.get_text(0, buf, sizeof(buf));
    TEST_ASSERT_STREQ(buf, "hello");
}

TEST(piece_table_delete_across_pieces) {
    PieceTable pt;
    pt.init_from_string("abc", 3);

    pt.insert(1, "XXX", 3);
    // Now: aXXXbc (3 pieces: a, XXX, bc)

    // Delete across piece boundary
    pt.delete_range(0, 3);
    // Now: Xbc

    char buf[32] = {0};
    pt.get_text(0, buf, sizeof(buf));
    TEST_ASSERT_STREQ(buf, "Xbc");
}

