// PieceTable - Line Operations
// ============================================================================

TEST(piece_table_count_lines_empty) {
    PieceTable pt;
    TEST_ASSERT_EQ(pt.count_lines(), 1u);
}

TEST(piece_table_count_lines_no_newlines) {
    PieceTable pt;
    pt.init_from_string("hello world", 11);
    TEST_ASSERT_EQ(pt.count_lines(), 1u);
}

TEST(piece_table_count_lines_one_newline) {
    PieceTable pt;
    pt.init_from_string("hello\nworld", 11);
    TEST_ASSERT_EQ(pt.count_lines(), 2u);
}

TEST(piece_table_count_lines_multiple) {
    PieceTable pt;
    pt.init_from_string("line1\nline2\nline3", 17);
    TEST_ASSERT_EQ(pt.count_lines(), 3u);
}

TEST(piece_table_count_lines_trailing_newline) {
    PieceTable pt;
    pt.init_from_string("line1\nline2\n", 12);
    TEST_ASSERT_EQ(pt.count_lines(), 3u);
}

TEST(piece_table_get_line_start) {
    PieceTable pt;
    pt.init_from_string("line1\nline2\nline3", 17);

    TEST_ASSERT_EQ(pt.get_line_start(0), 0u);
    TEST_ASSERT_EQ(pt.get_line_start(1), 6u);
    TEST_ASSERT_EQ(pt.get_line_start(2), 12u);
}

TEST(piece_table_byte_to_line) {
    PieceTable pt;
    pt.init_from_string("line1\nline2\nline3", 17);

    TEST_ASSERT_EQ(pt.byte_to_line(0), 0u);   // 'l' of line1
    TEST_ASSERT_EQ(pt.byte_to_line(5), 0u);   // '\n' after line1
    TEST_ASSERT_EQ(pt.byte_to_line(6), 1u);   // 'l' of line2
    TEST_ASSERT_EQ(pt.byte_to_line(11), 1u);  // '\n' after line2
    TEST_ASSERT_EQ(pt.byte_to_line(12), 2u);  // 'l' of line3
}

// ============================================================================
// PieceTable - Undo/Redo
// ============================================================================

TEST(piece_table_undo_initial_state) {
    PieceTable pt;
    TEST_ASSERT_FALSE(pt.can_undo());
    TEST_ASSERT_FALSE(pt.can_redo());
}

TEST(piece_table_undo_simple) {
    PieceTable pt;
    pt.init_from_string("hello", 5);

    pt.push_undo();
    pt.insert(5, " world", 6);

    TEST_ASSERT_TRUE(pt.can_undo());

    char buf[32] = {0};
    pt.get_text(0, buf, sizeof(buf));
    TEST_ASSERT_STREQ(buf, "hello world");

    // undo() returns cursor position (size_t), not bool
    pt.undo();

    memset(buf, 0, sizeof(buf));
    pt.get_text(0, buf, sizeof(buf));
    TEST_ASSERT_STREQ(buf, "hello");
}

TEST(piece_table_redo_simple) {
    PieceTable pt;
    pt.init_from_string("hello", 5);

    pt.push_undo();
    pt.insert(5, " world", 6);
    pt.undo();

    TEST_ASSERT_TRUE(pt.can_redo());
    // redo() returns cursor position (size_t), not bool
    pt.redo();

    char buf[32] = {0};
    pt.get_text(0, buf, sizeof(buf));
    TEST_ASSERT_STREQ(buf, "hello world");
}

TEST(piece_table_undo_multiple) {
    PieceTable pt;
    pt.init_from_string("a", 1);

    pt.push_undo();
    pt.insert(1, "b", 1);

    pt.push_undo();
    pt.insert(2, "c", 1);

    char buf[32] = {0};
    pt.get_text(0, buf, sizeof(buf));
    TEST_ASSERT_STREQ(buf, "abc");

    pt.undo();
    memset(buf, 0, sizeof(buf));
    pt.get_text(0, buf, sizeof(buf));
    TEST_ASSERT_STREQ(buf, "ab");

    pt.undo();
    memset(buf, 0, sizeof(buf));
    pt.get_text(0, buf, sizeof(buf));
    TEST_ASSERT_STREQ(buf, "a");
}

TEST(piece_table_undo_truncates_redo) {
    PieceTable pt;
    pt.init_from_string("a", 1);

    pt.push_undo();
    pt.insert(1, "b", 1);

    pt.push_undo();
    pt.insert(2, "c", 1);

    pt.undo(); // Back to "ab"

    // New edit should truncate redo history
    pt.push_undo();
    pt.insert(2, "X", 1);

    char buf[32] = {0};
    pt.get_text(0, buf, sizeof(buf));
    TEST_ASSERT_STREQ(buf, "abX");

    // Redo should not be available (history truncated)
    TEST_ASSERT_FALSE(pt.can_redo());
}

TEST(piece_table_undo_delete) {
    PieceTable pt;
    pt.init_from_string("hello", 5);

    pt.push_undo();
    pt.delete_range(1, 3);

    char buf[32] = {0};
    pt.get_text(0, buf, sizeof(buf));
    TEST_ASSERT_STREQ(buf, "ho");

    pt.undo();

    memset(buf, 0, sizeof(buf));
    pt.get_text(0, buf, sizeof(buf));
    TEST_ASSERT_STREQ(buf, "hello");
}

// ============================================================================
// PieceTable - Large Content
// ============================================================================

TEST(piece_table_large_content) {
    PieceTable pt;

    // Create a string with 10000 characters
    char large[10001];
    for (int i = 0; i < 10000; i++) {
        large[i] = 'a' + (i % 26);
    }
    large[10000] = '\0';

    pt.init_from_string(large, 10000);
    TEST_ASSERT_EQ(pt.total_length(), 10000u);

    // Verify content
    char buf[10001] = {0};
    size_t len = pt.get_text(0, buf, sizeof(buf));
    TEST_ASSERT_EQ(len, 10000u);
    TEST_ASSERT_MEMEQ(buf, large, 10000);
}

TEST(piece_table_many_inserts) {
    PieceTable pt;
    pt.init_from_string("", 0);

    // Insert 1000 single characters
    for (int i = 0; i < 1000; i++) {
        char c = 'a' + (i % 26);
        pt.insert(pt.total_length(), &c, 1);
    }

    TEST_ASSERT_EQ(pt.total_length(), 1000u);
}

// ============================================================================
// TextDocument Tests
// ============================================================================

TEST(text_document_from_string) {
    TextDocument* doc = TextDocument::from_string("hello world");
    TEST_ASSERT_NOT_NULL(doc);
    TEST_ASSERT_EQ(doc->length(), 11u);
    TEST_ASSERT_FALSE(doc->is_dirty());

    delete doc;
}

TEST(text_document_dirty_on_insert) {
    TextDocument* doc = TextDocument::from_string("hello");
    TEST_ASSERT_FALSE(doc->is_dirty());

    doc->insert(5, " world", 6);
    TEST_ASSERT_TRUE(doc->is_dirty());

    delete doc;
}

TEST(text_document_dirty_on_delete) {
    TextDocument* doc = TextDocument::from_string("hello world");
    doc->delete_range(5, 6);
    TEST_ASSERT_TRUE(doc->is_dirty());

    delete doc;
}

TEST(text_document_mark_clean) {
    TextDocument* doc = TextDocument::from_string("hello");
    doc->insert(5, " world", 6);
    TEST_ASSERT_TRUE(doc->is_dirty());

    doc->mark_clean();
    TEST_ASSERT_FALSE(doc->is_dirty());

    delete doc;
}

TEST(text_document_line_ending_detection_lf) {
    TextDocument* doc = TextDocument::from_string("line1\nline2");
    TEST_ASSERT_EQ(doc->get_line_ending(), LineEnding::LF);
    delete doc;
}

TEST(text_document_line_ending_detection_crlf) {
    TextDocument* doc = TextDocument::from_string("line1\r\nline2");
    TEST_ASSERT_EQ(doc->get_line_ending(), LineEnding::CRLF);
    delete doc;
}

TEST(text_document_undo_redo) {
    TextDocument* doc = TextDocument::from_string("hello");

    doc->push_undo();
    doc->insert(5, " world", 6);

    TEST_ASSERT_EQ(doc->length(), 11u);

    doc->undo();
    TEST_ASSERT_EQ(doc->length(), 5u);

    doc->redo();
    TEST_ASSERT_EQ(doc->length(), 11u);

    delete doc;
}

TEST(text_document_line_count) {
    TextDocument* doc = TextDocument::from_string("line1\nline2\nline3");
    TEST_ASSERT_EQ(doc->line_count(), 3u);
    delete doc;
}
